import React, { useContext } from "react";
import { Link } from "react-router-dom";
import { GeneralContext } from "./GeneralContext";

const Orders = () => {
  // Safe default fallback array to prevent crash if undefined
  const { allOrders = [] } = useContext(GeneralContext);

  return (
    <div className="orders-container">
      {allOrders.length === 0 ? (
        <div className="no-orders">
          <p>You haven't placed any orders today</p>
          <Link to="/" className="btn">
            Get started
          </Link>
        </div>
      ) : (
        <>
          {/* Section match for Dashboard typography layout style */}
          <div className="orders-header">
            <h6>Orders ({allOrders.length})</h6>
            <hr className="divider" />
          </div>

          <div className="table-container">
            <table className="orders-table">
              <thead>
                <tr>
                  <th>Instrument</th>
                  <th>Qty.</th>
                  <th>Price</th>
                  <th>Status</th>
                  <th>Mode</th>
                </tr>
              </thead>
              <tbody>
                {allOrders.map((order, index) => (
                  <tr key={index}>
                    <td className="instrument-name">{order.name}</td>
                    <td>{order.qty}</td>
                    <td>{order.price.toFixed(2)}</td>
                    <td>
                      <span className="status-badge executed">EXECUTED</span>
                    </td>
                    <td>
                      <span
                        className={`mode-badge ${
                          order.mode === "BUY" ? "buy" : "sell"
                        }`}
                      >
                        {order.mode}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}
    </div>
  );
};

export default Orders;
